def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    slide_number = 5
    target_text = 'Published findings in 1898'
    prs = Presentation(modified_ppt_path)
    try:
        slide = prs.slides[slide_number-1]
    except IndexError:
        return f"Slide {slide_number} does not exist in modified PPT.", 0.0
    bullet_texts = []
    for shape in slide.shapes:
        if shape.has_text_frame:
            for para in shape.text_frame.paragraphs:
                if para.text.strip():
                    bullet_texts.append(para.text.strip())

    # Check the second to last text element, as the footer is also present as a text frame
    if bullet_texts and bullet_texts[-2] == target_text:
        return "Bullet point correctly added at the end.", 1.0
    elif target_text in bullet_texts:
        return "Bullet point present but not at end.", 0.0
    else:
        return "Bullet point not found.", 0.0

